import {
  html,
  customElement,
  state,
} from "@umbraco-cms/backoffice/external/lit";
import { UmbWorkspaceViewElement } from "@umbraco-cms/backoffice/workspace";
import type { FormSecurityForGroup } from "@umbraco-forms/generated";
import type { UUIBooleanInputEvent } from "@umbraco-cms/backoffice/external/uui";
import { FORMS_SECURITY_USER_GROUP_WORKSPACE_CONTEXT } from "../../security-user-group-workspace.context-token.js";
import type { PackagePermissionsSecurityBase } from "../../../entities.js";
import type { FormsSecurityUserGroupWorkspaceContext } from "../../security-user-group-workspace.context.js";
import { UmbWorkspaceViewSecurityPermissionsBaseElement } from "./workspace-view-security-permissions-base.element.js";

const elementName = "workspace-view-security-user-group-permissions";

@customElement(elementName)
export class UmbWorkspaceViewSecurityUserGroupPermissionsElement
  extends UmbWorkspaceViewSecurityPermissionsBaseElement<FormsSecurityUserGroupWorkspaceContext>
  implements UmbWorkspaceViewElement
{
  @state()
  _security?: FormSecurityForGroup;

  constructor() {
    super(FORMS_SECURITY_USER_GROUP_WORKSPACE_CONTEXT.contextAlias);
  }

  observeSecurityItem() {
    if (!this.workspaceContext) return;

    this.observe(this.workspaceContext.data, (security) => {
      if (!security) return;
      this._security = security;
    });
  }

  onPackagePermissionsChange(
    e: UUIBooleanInputEvent,
    permission: keyof PackagePermissionsSecurityBase
  ) {
    const value = e.target.checked;
    this.workspaceContext?.setUserGroupSecurityProperty(permission, value);

    if (permission === "viewEntries" && !value) {
      this.workspaceContext?.setUserGroupSecurityProperty("editEntries", false);
      this.workspaceContext?.setUserGroupSecurityProperty("deleteEntries", false);
    }

    this.dispatchEvent(new CustomEvent("valueChange"));
    this.requestUpdate();
  }

  render() {
    return html` ${this.renderToggles(this._security?.userGroupSecurity)}
    ${this.renderStartFolders(this._security?.startFolderIds ?? [])}
    ${this.renderSecurityTable(this._security?.formsSecurity ?? [])}`;
  }
}

export default UmbWorkspaceViewSecurityUserGroupPermissionsElement;

declare global {
  interface HTMLElementTagNameMap {
    [elementName]: UmbWorkspaceViewSecurityUserGroupPermissionsElement;
  }
}
